proof fn phi_3_frame_size_positive_from_entry(d: Directory, i: nat, va: nat, pte: PTE)
    requires
        d.inv(),
        i < d.entries.len(),
        d.interp_of_entry(i).contains_pair(va, pte),
    ensures
        pte.frame.size > 0,
{
    d.lemma_interp_of_entry_between(i, va, pte);
}

proof fn phi_4_frame_fits_within_single_entry(d: Directory, i: nat, va: nat, pte: PTE)
    requires
        d.inv(),
        i < d.entries.len(),
        d.interp_of_entry(i).contains_pair(va, pte),
    ensures
        pte.frame.size <= d.entry_size(),
{
    d.lemma_interp_of_entry_between(i, va, pte);
}
